import React, { useState, useEffect } from 'react';
import { accountsPayableAPI } from '../services/api';
import toast from 'react-hot-toast';
import {
  Calendar,
  DollarSign,
  AlertTriangle
} from 'lucide-react';

const AccountsPayable = () => {
  const [accounts, setAccounts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchAccounts();
  }, []);

  const fetchAccounts = async () => {
    try {
      const response = await accountsPayableAPI.getAll();
      setAccounts(response.data.data);
    } catch (error) {
      toast.error('Error al cargar cuentas por pagar');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: 'MXN'
    }).format(amount);
  };

  const isOverdue = (dueDate) => {
    return new Date(dueDate) < new Date();
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900">Cuentas por Pagar</h1>
          <p className="mt-1 text-sm text-gray-600">
            Gestiona los pagos a tus proveedores
          </p>
        </div>
      </div>

      {/* Accounts Table */}
      <div className="card">
        <div className="overflow-x-auto">
          <table className="table">
            <thead>
              <tr>
                <th>Proveedor</th>
                <th>Factura</th>
                <th>Monto Total</th>
                <th>Saldo Pendiente</th>
                <th>Fecha Vencimiento</th>
                <th>Estado</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {accounts.map((account) => (
                <tr key={account._id}>
                  <td>{account.proveedor?.name}</td>
                  <td>{account.compra?.invoice || 'N/A'}</td>
                  <td className="text-right font-medium">
                    {formatCurrency(account.monto)}
                  </td>
                  <td className="text-right font-medium">
                    {formatCurrency(account.saldo)}
                  </td>
                  <td>
                    <div className="flex items-center">
                      <Calendar className="h-4 w-4 mr-2" />
                      {new Date(account.dueDate).toLocaleDateString('es-MX')}
                      {isOverdue(account.dueDate) && (
                        <AlertTriangle className="h-4 w-4 ml-2 text-danger-600" />
                      )}
                    </div>
                  </td>
                  <td>
                    <span className={`badge badge-${
                      account.status === 'pagado' ? 'success' :
                      account.status === 'vencido' ? 'danger' : 'warning'
                    }`}>
                      {account.status}
                    </span>
                  </td>
                  <td>
                    {account.status === 'pendiente' && (
                      <button className="btn btn-success btn-sm">
                        <DollarSign className="h-4 w-4 mr-1" />
                        Pagar
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AccountsPayable;
